import React from 'react';

function ComposantMapping() {
    // Un tableau de données (par exemple, une liste de prénoms)
    const listeUtilisateurs = ["Alice", "Bob", "Charlie", "Diana"];

    return (
        <div>
            <h2>Consigne 2 : Mapping (boucle map)</h2>
            <ul>
                {/* On boucle sur le tableau pour créer un <li> pour chaque utilisateur */}
                {listeUtilisateurs.map((utilisateur, index) => (
                    // N'oublie pas la prop "key" qui est obligatoire en React lors d'un map !
                    <li key={index}>{utilisateur}</li>
                ))}
            </ul>
        </div>
    );
}

export default ComposantMapping;
